"""
MKT Original Commentary — 2 Kings chapters 24–25 (fill)
Run: python3 scripts/zc-original-2kings-24-25-fill.py

Fills missing verses in 2 Kings 24–25: the fall of Jerusalem, Babylonian deportations,
and the book's ambiguous closing note on Jehoiachin. Existing entries (ch24:14; ch25:9,27)
are not overwritten.

Key decisions:
- ʿal pî YHWH formula (24:3) treated as theological fulfillment-marker
- Zedekiah's blinding (25:7) as covenant-curse vocabulary (Deut 28:28-29)
- Temple inventory (25:13-17) as theological testimony to what the covenant had built
- Gedaliah narrative (25:22-26) as the failure of remnant-hope under assassination
- Closing Jehoiachin note (25:27-30, partial) as open-ended covenant seed
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

FILL = {
  "24": {
    "1": "<p><em>Bāyāmîm hāhēm</em> (in those days) — the temporal marker tying Jehoiakim&rsquo;s reign to the broader Assyrian-to-Babylonian power shift. <em>ʿālāh nᵉḇûḵaḏneʾṣṣar</em> — Nebuchadnezzar came up — the same verb (<em>ʿālāh</em>) used for military campaigns throughout Kings; the king of Babylon performs the same ascending action that YHWH&rsquo;s judgment-agents always perform. Jehoiakim &lsquo;became his servant three years&rsquo; — <em>wayyᵉhî lô ʿeḇeḏ šālōš šānîm</em> — the vassal relation encoded in <em>ʿeḇeḏ</em> (servant/slave), the same word used for Israel&rsquo;s slavery in Egypt. Then <em>wayyāšob wayyimrōḏ bô</em> — he turned and rebelled — <em>māraḏ</em> is the covenant-rebellion verb, used for Moab&rsquo;s rebellion (3:5) and the suzerain-vassal defection formula throughout the Ancient Near East.</p>",
    "2": "<p><em>wayyšallah YHWH bô</em> — YHWH sent against him — the <em>šillah</em> verb marks direct divine agency: YHWH dispatches the raiding bands as instruments of covenant judgment. The coalition of Chaldeans, Syrians, Moabites, and Ammonites are all former enemies of Israel now conscripted into service as YHWH&rsquo;s punitive agents. The pattern is Deuteronomic: when Israel sins, YHWH uses surrounding nations as the covenant sword (Deut 28:25, 49-52). <em>gĕdûdê</em> (bands/raiding parties) — the same word used for the Syrian raiding bands of 5:2; the military form of the judgment is calibrated — irregular bands before the full siege army of ch25.</p>",
    "3": "<p><em>ʿal pî YHWH</em> — at the mouth/command of YHWH — the fulfillment-formula the narrator uses to interpret historical events as YHWH&rsquo;s direct causation. This phrase appears at key theological turning points (2 Kings 1:17; 9:26; 23:16; 24:2) where the narrator insists that political history is the execution of YHWH&rsquo;s word. <em>lᵉhasîr meʿal pānāyw</em> — to remove from before his face — the preposition <em>meʿal pānāyw</em> (from before his face) is precisely the language of divine presence and its withdrawal; to be removed from before YHWH&rsquo;s face is to lose covenant access. The specific grounds: <em>bᵉḵol ḥaṭṭōʾt mᵉnaššeh</em> — the sins of Manasseh — the narrator locates the final cause in ch21&rsquo;s theological nadir.</p>",
    "4": "<p><em>wᵉgam dām hannāqî ʾăšer šāpaḵ</em> — and also the innocent blood that he shed — <em>dām nāqî</em> (innocent blood) is a legal term with specific covenant weight: the shedding of innocent blood defiles the land itself and cannot be expiated except by the blood of the one who shed it (Num 35:33; Deut 19:10). The phrase <em>waymallēʾ ʾet yᵉrûšālaim dām nāqî</em> (he filled Jerusalem with innocent blood) — <em>mālaʾ</em> (filled) is the same root as YHWH filling the temple with glory; here the city is filled with judicial defilement rather than divine presence. The irreversibility — <em>wᵉlōʾ ʾābāh YHWH lisloaḥ</em>, YHWH was not willing to forgive — uses the verb <em>ʾābāh</em> (to be willing/consent), marking a divine refusal rather than an inability to forgive.</p>",
    "5": "<p><em>wᵉyeter diḇrê yᵉhôyāqîm wᵉkol ʾăšer ʿāśāh</em> — the rest of the acts of Jehoiakim and all that he did — the standard regnal summary formula functioning here as an abrupt closure. The formula typically refers the reader to the annals of the kings of Judah; here the narrator declines to elaborate, treating Jehoiakim&rsquo;s reign as having been adequately characterized by the Babylonian capitulation and the note about innocent blood. The terseness is itself evaluative: this is a king not worth extending commentary on.</p>",
    "6": "<p><em>wayyiškab yᵉhôyāqîm ʿim ʾăḇōtāyw</em> — Jehoiakim slept with his fathers — the death formula for Judean kings, here applied without the usual notation of burial in the city of David, suggesting an undignified end (cf. Jer 22:18-19 which prophesied he would be &lsquo;buried with the burial of a donkey&rsquo;). <em>wayyimloḵ yᵉhôyāḵîn bᵉnô taḥtāyw</em> — Jehoiachin his son reigned in his place — the succession formula; the name <em>Yᵉhôyāḵîn</em> (YHWH establishes/sustains) will be crucial to the book&rsquo;s closing note (25:27-30), where the Davidic seed is paradoxically &lsquo;established&rsquo; in Babylonian exile.</p>",
    "7": "<p><em>wᵉlōʾ yāsap ʿôḏ melek miṣrayim lāṣēʾt mēʾarṣô</em> — the king of Egypt no longer came out from his land — the imperfect with <em>lōʾ yāsap</em> (did not again/no more) marks a permanent geopolitical shift. The great imperial rival of Assyrian-era Judah has been neutralized: <em>kî lāqaḥ melek bāḇel mikkaḥ naḥal miṣrayim ʿaḏ nᵉhar pĕrāt</em>, the king of Babylon took everything from the Wadi of Egypt to the Euphrates River. The Euphrates boundary is the Abrahamic covenant promise-extent (Gen 15:18); its seizure by Babylon marks the complete reversal of the Davidic high point: what was the covenant&rsquo;s eastern reach is now Babylon&rsquo;s western border.</p>",
    "8": "<p><em>ben šᵉmōneh ʿeśrēh šānāh yᵉhôyāḵîn bᵉmolḵô</em> — Jehoiachin was eighteen years old when he became king — the regnal age formula positions him as a young king (contrast v1, Jehoiakim&rsquo;s longer reign). <em>šᵉlōšāh ḥoḏāšîm mālaḵ bîrûšālāim</em> — three months he reigned in Jerusalem — one of the shortest reigns recorded; the brevity underscores the futility of Judean kingship at this stage. The narrator uses the standard form even for a reign so short that it barely registers, maintaining the covenantal accounting structure that records every Davidic king regardless of duration.</p>",
    "9": "<p><em>wayyaʿaś hārāʿ bᵉʿênê YHWH</em> — he did evil in the eyes of YHWH — the covenant-evaluation formula applied even to a king who reigned only three months. The formula&rsquo;s consistent application regardless of reign length reflects the narrator&rsquo;s insistence that every Davidic king is evaluated against the covenant standard, not merely against political outcomes. <em>kᵉkōl ʾăšer ʿāśāh ʾāḇîw</em> — according to all that his father had done — the continuity of apostasy through the family line; the verb <em>ʿāśāh</em> (did/made) links father and son in a shared moral pattern.</p>",
    "10": "<p><em>bāʿēt hahîʾ ʿālû ʿaḇdê nᵉḇûḵaḏneʾṣṣar</em> — at that time the servants of Nebuchadnezzar came up — <em>bāʿēt hahîʾ</em> (at that time) ties the Babylonian siege to the reign of Jehoiachin, the narrator holding timeline and theological judgment together. The plural <em>ʿāḇdê</em> (servants) — Nebuchadnezzar&rsquo;s subordinates arrive first, before the king himself (v11). The city is put under siege — <em>wayyābōʾ hāʿîr bammāṣôr</em> — the word <em>māṣôr</em> (siege/siege-work) carries military and legal weight: the siege is the covenant curse of Deut 28:52-57 enacted in history.</p>",
    "11": "<p><em>ûnᵉḇûḵaḏneʾṣṣar melek bāḇel bāʾ ʿal hāʿîr</em> — Nebuchadnezzar king of Babylon came to the city — the king himself arrives, elevating the personal weight of the confrontation. The grammar puts Nebuchadnezzar in parallel with David&rsquo;s capture of Jerusalem from the Jebusites (2 Sam 5:6-9): as David came against the city and took it, Nebuchadnezzar comes against David&rsquo;s city. The reversal is total: the city won by the first David is being taken by the king who will end the Davidic political order. <em>wayyiṣbᵉʾû ʿālayw ʿăḇāḏāyw</em> — his servants were besieging it — the pluperfect-sequential indicating that the servants&rsquo; siege was already underway when the king arrived.</p>",
    "12": "<p><em>wayyēṣēʾ yᵉhôyāḵîn melek yᵉhûḏāh</em> — Jehoiachin king of Judah went out — the verb <em>yāṣāʾ</em> (went out) for voluntary surrender is the exact opposite of the king&rsquo;s expected role of defending or fleeing. <em>ʿal melek bāḇel hûʾ wᵉʾimmô wᵉʿaḇāḏāyw wᵉśārāyw wᵉsārîsāyw</em> — to the king of Babylon, he and his mother and his servants and his princes and his officials — the entire court surrenders en masse; the vocabulary itemizes the covenant-community of the king (mother, servants, princes, officials). The specific note of the king&rsquo;s mother (<em>ʾimmô</em>) is significant: the queen-mother in Judah holds a formal institutional role, and her surrender marks the end of that office&rsquo;s Davidic iteration.</p>",
    "13": "<p><em>wayyōṣēʾ miššām ʾet kol ʾôṣrôt bêt YHWH wᵉʾôṣrôt bêt hammelek</em> — he took from there all the treasuries of the house of YHWH and the treasuries of the king&rsquo;s house — the stripping of the temple treasuries is narrated with the same verb <em>yāṣāʾ</em> (went out, brought out) used for the king&rsquo;s surrender in v12; both the king and the treasure are &lsquo;brought out&rsquo; to Babylon. <em>wayyᵉqaṣṣēṣ ʾet kol kᵉlê hazzāhāḇ</em> — he cut in pieces all the vessels of gold — <em>qāṣaṣ</em> (cut to pieces) is a term of violent reduction; the gold vessels made by Solomon for worship are dismembered. The narrator cites Solomon&rsquo;s specific decree (<em>ʾăšer ʿāśāh šᵉlōmōh melek yiśrāʾēl bᵉhêḵal YHWH kaʾăšer dibbēr YHWH</em>) — as YHWH had spoken — invoking the fulfillment of the prophetic word about the temple&rsquo;s despoliation (1 Kings 9:7-9).</p>",
    "15": "<p><em>wayyegeleh ʾet yᵉhôyāḵîn bāḇelāh</em> — he exiled Jehoiachin to Babylon — the <em>gālāh</em> (exile/uncover) verb is the central lexeme of the exile narrative: deportation as uncovering/stripping, the opposite of YHWH&rsquo;s covering of his people. The inventory of the deportees is precise: the king&rsquo;s mother, wives, officials, and the leaders of the land (<em>ʾêlê hāʾāreṣ</em> — the powerful/mighty ones of the land). The word <em>ʾêlê</em> (terebinths/mighty ones) is a poetic term for the élite; the exile strips the land of its most powerful. Jehoiachin will be in Babylon for 37 years before the book&rsquo;s closing scene of release (25:27).</p>",
    "16": "<p><em>wᵉkol ʾanšê hehayil šiḇʿat ʾălāpîm</em> — all the men of valor, seven thousand — the military élite deported as a security measure, consistent with Babylonian imperial policy of decapitating captured nations by removing their fighting class. <em>wehheḥārāš wᵉhammassēr ʾelep</em> — the craftsmen and smiths, one thousand — the artisan class deported to serve Babylonian industry and to prevent the production of weapons in Judah. The deportation of skilled workers is documented in Assyrian and Babylonian administrative texts; the narrator uses the same categories. The two classes — warriors and craftsmen — are the embodiment of the covenant people&rsquo;s civilizational capacity; their exile signals the end of Judah as a functioning state.</p>",
    "17": "<p><em>wayyamliḵ melek bāḇel ʾet mattanyāh dōḏô taḥtāyw</em> — the king of Babylon made Mattaniah his uncle king in his place — the <em>wayyamliḵ</em> (causative: caused to reign) marks Babylonian installation of a client king; the sovereignty now rests with Nebuchadnezzar, not with the Davidic line itself. The name-change from Mattaniah to Zedekiah — <em>wayyāsēb ʾet šᵉmô ṣiḏqiyyāhû</em> — is a political act: renaming a vassal was a Near Eastern assertion of suzerainty (cf. the renaming of Daniel and his companions in Dan 1:7). The new name <em>Ṣiḏqiyyāhû</em> (YHWH is my righteousness) is theologically ironic: the king whose reign will end in covenant catastrophe bears a name that invokes covenantal fidelity.</p>",
    "18": "<p><em>ben ʿeśrîm wᵉʾaḥat šānāh ṣiḏqiyyāhû bᵉmolḵô ûšᵉtêʿeśrēh šānāh mālaḵ bîrûšālāim</em> — standard regnal formula for Zedekiah: 21 years old, eleven-year reign. The eleven-year detail is significant: long enough to have fostered hope but ending in the complete destruction of ch25. The mother-name (<em>wᵉšēm ʾimmô ḥamûṭal bat yirmᵉyāhû millibᵉnāh</em>) connects Zedekiah to the same maternal line as Jehoahaz (23:31); both share the same mother from Libnah. The family genealogy is maintained in the formulaic record even as the kingdom collapses — the covenant accounting continues.</p>",
    "19": "<p><em>wayyaʿaś hārāʿ bᵉʿênê YHWH kᵉkōl ʾăšer ʿāśāh yᵉhôyāqîm</em> — he did evil in the eyes of YHWH according to all that Jehoiakim had done — the covenant-evaluation formula aligning Zedekiah with his predecessor. The phrase <em>kᵉkōl ʾăšer ʿāśāh</em> (according to all that ... had done) creates a genealogy of apostasy: Manasseh&rsquo;s wickedness becomes the benchmark (23:26), and subsequent kings are measured against it and against each other in a descending spiral. The imperfect verb <em>ʿāśāh</em> in the formula always describes a completed, evaluated pattern of behavior, not a single act.</p>",
    "20": "<p><em>kî ʿal ʾap YHWH hāyᵉtāh bîrûšālaim wîhûḏāh ʿaḏ hiššᵉlîḵô ʾōtām mēʿal pānāyw</em> — for through the anger of YHWH it happened to Jerusalem and Judah until he had cast them out from his presence — the verse is the theological conclusion to ch24, interpreting the entire sequence of deportations and political disasters as the outworking of divine anger (<em>ʾap</em>, nose/anger — the somatic Hebrew idiom for intense emotion). The verb <em>hiššᵉlîḵô</em> (cast out) is the expulsion-from-presence verb used for Adam and Eve in Gen 3:23-24 (<em>gāraš</em>), establishing exile as the eschatological form of the garden expulsion. <em>ûṣiḏqiyyāhû māraḏ bᵉmelek bāḇel</em> — Zedekiah rebelled against the king of Babylon — <em>māraḏ</em> (rebel) setting up ch25&rsquo;s catastrophe.</p>"
  },
  "25": {
    "1": "<p><em>wayhî biššᵉnat haттᵉšîʿît lᵉmolḵô baḥōḏeš hāʿăśîrî ʿăśārāh laḥōḏeš</em> — in the ninth year of his reign, in the tenth month, on the tenth day of the month — the narrator&rsquo;s precise dating (year, month, day) elevates this event to the calendrical gravity of a feast or fast; indeed, this date becomes a fast day in the Judean calendar (Zech 8:19). <em>bāʾ nᵉḇûḵaḏneʾṣṣar melek bāḇel hûʾ wᵉḵol ḥêlô</em> — Nebuchadnezzar came, he and all his army — the personal and corporate arrival formula mirrors the formulaic language for divine theophany: the coming of the great king with his whole army. <em>wayyiḥan ʿālayw wayyiḇnû ʿālayw dāyēq sāḇîḇ</em> — he encamped against it and built a siege ramp around it — <em>dāyēq</em> (siege ramp/siege wall) is a loanword in some analyses; the siege-infrastructure vocabulary is technical military language.</p>",
    "2": "<p><em>wayyābōʾ hāʿîr bammāṣôr ʿad ʿaśtê ʿeśrēh šānāh</em> — the city came under siege until the eleventh year of Zedekiah — the duration of the siege (roughly 18 months from the 9th to the 11th year) is recorded as the temporal frame of the catastrophe. The verb construction <em>wayyābōʾ ... bammāṣôr</em> (came ... under siege) presents the city itself as the subject, as if Jerusalem entered a new state. The length of the siege — survivable, protracted, grinding — is the form of covenant curse detailed in Deut 28:52-57: the siege that reduces the city to cannibalism and starvation before the final breach.</p>",
    "3": "<p><em>baḥōḏeš hārᵉḇîʿî bᵉtišʿāh laḥōḏeš wayyeḥezaq hārāʿāḇ bāʿîr</em> — in the fourth month, on the ninth of the month, the famine was severe in the city — <em>ḥāzaq</em> (was severe/prevailed/was strong) is the same verb used for YHWH&rsquo;s hand being strong against enemies; here the famine is the agent of YHWH&rsquo;s covenant judgment, its severity expressed in the language of warfare. <em>wᵉlōʾ hāyāh lehem lᵉʿam hāʾāreṣ</em> — there was no bread for the people of the land — the covenant curse of Deut 28:17 (no grain in basket or kneading bowl) enacted. The phrase <em>ʿam hāʾāreṣ</em> (people of the land) here refers to the common population, distinct from the military and court élite who have already been deported.</p>",
    "4": "<p><em>tippāqaʿ hāʿîr</em> — the city was breached — <em>bāqaʿ</em> (niphal: was split/breached) is the same verb used for the splitting of the Red Sea (Exod 14:21 in some forms) and for rivers splitting (Ps 78:13); the irony is total: the waters that split to save Israel at the Exodus now the walls of Jerusalem split to end the Davidic kingdom. <em>wayyibrᵉḥû kol ʾanšê hammilḥāmāh hallaylāh</em> — all the men of war fled at night — the night-flight echoes the Passover night and the escape from Egypt, but in reverse: Israel&rsquo;s flight from Egypt was night-departure toward freedom; the flight from Jerusalem is night-departure toward destruction. The king goes &lsquo;toward the Arabah&rsquo; (<em>derek hāʿărāḇāh</em>), fleeing toward the Jordan wilderness — the same wilderness through which Joshua had led Israel into the land.</p>",
    "5": "<p><em>wayyirḏᵉpû ḥêl kaśḏîm ʾaḥar hammelek wayyaśśîgû ʾōtô bᵉʿarᵉḇôt yᵉrēḥô</em> — the Chaldean army pursued the king and overtook him in the plains of Jericho — the geographical precision is pointed: Jericho is the first city Israel conquered under Joshua; it is the city where the entry into the land began. The end of the Davidic kingdom occurs at the same place the covenant began to be embodied in land and conquest. <em>wayyāpĕṣû mēʾalāyw kol ḥêlô</em> — all his army scattered from him — the scattering of the shepherd&rsquo;s army (Zech 13:7: &lsquo;strike the shepherd, that the sheep may be scattered&rsquo;) — the fulfillment of the Deuteronomic threat of military dissolution before enemies (Deut 28:25).</p>",
    "6": "<p><em>wayyitpᵉśû ʾet hammelek wayyaʿălû ʾōtô ʾel melek bāḇel riblātāh</em> — they seized the king and brought him up to the king of Babylon at Riblah — the verb <em>tāpaś</em> (seized/apprehended) is used elsewhere for taking captives in war; the Davidic king is reduced to a prisoner of war. Riblah in the land of Hamath is the Babylonian headquarters in Syria — the same place where Pharaoh Necho had deposed Jehoahaz (23:33). Two Judean kings in succession are brought before foreign kings at Riblah; the legal venue underscores that Judah has become a subject people whose king must answer to a foreign court. <em>wayyᵉdabbᵉrû ʾittô mišpāṭ</em> — they pronounced judgment on him — <em>mišpāṭ</em> (judgment/sentence) using the covenant-law vocabulary for judicial verdict.</p>",
    "7": "<p><em>wᵉʾet bᵉnê ṣiḏqiyyāhû šāḥaṭû lᵉʿênāyw</em> — they slaughtered Zedekiah&rsquo;s sons before his eyes — <em>šāḥaṭ</em> (slaughter) is the term for the slaughter of animals for sacrifice; its application to the king&rsquo;s sons is deliberately brutal, evoking ritual killing. The death of the sons before Zedekiah&rsquo;s eyes is designed as the last thing he sees: <em>wᵉʾet ʿênê ṣiḏqiyyāhû ʿiwwēr</em> — and Zedekiah&rsquo;s eyes they blinded — <em>ʿiwwēr</em> (piel: blinded) is the covenant-curse of Deut 28:28-29 (&lsquo;YHWH will strike you with madness, blindness...&rsquo;). The last image Zedekiah sees is the death of his seed; he is then blinded so that this last image is, in a sense, his permanent vision. <em>wayyaʾaśrēhû baněḥuštayim</em> — they bound him in bronze shackles — <em>nᵉḥuštayim</em> (dual: bronze chains), possibly the same bronze that the Solomonic temple was adorned with, now used to bind its king.</p>",
    "8": "<p><em>ûḇaḥōḏeš haḥămiššî bᵉšiḇʿāh laḥōḏeš</em> — in the fifth month, on the seventh day of the month — the precise date continues the calendrical weight of ch25; this date also becomes a fast day (Zech 7:3; 8:19). <em>nᵉḇûzarʾaḏān rab ṭabbāḥîm</em> — Nebuzaradan the captain of the guard — <em>rab ṭabbāḥîm</em> literally &lsquo;chief of the slaughterers/executioners&rsquo;; the same root as <em>šāḥaṭ</em> used for the slaughter of Zedekiah&rsquo;s sons. The executioner-in-chief arrives to complete the work of destruction. <em>ʿeḇeḏ melek bāḇel</em> — servant of the king of Babylon — the title marking him as the foreign king&rsquo;s delegate; in the narrative structure, this servant of Babylon&rsquo;s king does what YHWH&rsquo;s servants (the prophets) warned would happen if Israel did not return to YHWH&rsquo;s service.</p>",
    "10": "<p><em>wᵉʾēt ḥômot yᵉrûšālaim sāḇîḇ nātᵉṣû kol ḥêl kaśḏîm</em> — all the Chaldean army tore down the walls of Jerusalem around it — the destruction of the walls (<em>ḥômāh</em>) reverses the covenant symbol of the city&rsquo;s protection: throughout the Psalms, YHWH was the wall and fortress of Zion (Ps 46:5; 48:12-13), and now the physical walls come down. The verb <em>nāṭaṣ</em> (tore down/broke down) is the same word used for the prophetic mandate to break down before building (Jer 1:10); here the breaking down is judgment, not preparation for renewal. The surrounding phrase <em>sāḇîḇ</em> (around/surrounding) echoes the siege language of v1: the army that surrounded the city now tears down what it surrounded.</p>",
    "11": "<p><em>wᵉʾēt yeter hāʿām hannišʾārîm bāʿîr</em> — the rest of the people who remained in the city — the vocabulary of remnant (<em>yeter</em>, remainder; <em>nišʾārîm</em>, those left over) is heavily theological: the remnant that was not deported in the first two waves (ch24:14-16) is now also taken. <em>wᵉʾet hahōlᵉlîm ʾăšer nāplû ʾel melek bāḇel</em> — and the deserters who had gone over to the king of Babylon — <em>nāpal ʾel</em> (fell to/deserted to) is the verb for surrendering to an enemy king; those who had capitulated voluntarily are treated with the same exile as those who were captured, collapsing the distinction between resistance and surrender in the mechanics of empire.</p>",
    "12": "<p><em>ûmidallôt hāʾāreṣ hišʾîr rab ṭabbāḥîm lᵉkōrᵉmîm ûlᵉyōgᵉḇîm</em> — from the poorest of the land the captain of the guard left some as vinedressers and farmers — <em>dallôt</em> (poorest/thin ones, from <em>ḏal</em>, weak/thin/poor) designates the agricultural underclass without military value. The Babylonian policy preserved the working poor to maintain the land&rsquo;s agricultural productivity — a pragmatic imperial decision. The word <em>kōrᵉmîm</em> (vinedressers) evokes the vine-imagery of covenant blessing (Deut 8:8; Isa 5:1-7); the vine of YHWH&rsquo;s people is tended now by the &lsquo;poor&rsquo; left behind, the covenant community reduced to its bare subsistence minimum.</p>",
    "13": "<p><em>wᵉʾet ʿammûḏê hannᵉḥōšet ʾăšer bêt YHWH</em> — the bronze pillars that were in the house of YHWH — the Chronicler begins the inventory of the temple furnishings with the pillars (Jachin and Boaz, 1 Kings 7:15-22); their bronze had been brought as spoil from David&rsquo;s wars (2 Sam 8:8) and their names encoded covenant theology (&lsquo;he establishes&rsquo; and &lsquo;in him is strength&rsquo;). <em>šibbar hakaśḏîm</em> — the Chaldeans broke to pieces — <em>šāḇar</em> (broke) is used for the breaking of the covenant tablets (Exod 32:19), making the destruction of the temple furniture a visual counterpart of covenant rupture. <em>wayyiśśᵉʾû ʾet nᵉḥuštām bāḇelāh</em> — and they carried their bronze to Babylon — the movement of the temple metal reverses the movement of the Exodus spoils; what came out of Egypt as covenant wealth is now carried back eastward to an empire.</p>",
    "14": "<p><em>wᵉʾet haśśîrôt wᵉʾet hayya ʿîm wᵉʾet hamᵉzammᵉrôt</em> — the pots, shovels, and snuffers — the inventory of smaller liturgical vessels continues the theological accounting of what the covenant community had accumulated for worship. The objects are all implements of the sacrificial system: pots for cooking sacrificial meat, shovels for removing ash, snuffers for the lampstand. <em>wᵉʾēt kol kᵉlê hannᵉḥōšet ʾăšer yᵉšārᵉtû bāhem</em> — all the bronze vessels with which they ministered — the verb <em>šārat</em> (minister/serve) is the Levitical service term; the objects of priestly ministry are stripped from the context of worship and carried to Babylon as plunder.</p>",
    "15": "<p><em>wᵉʾet hammaḥtôt wᵉʾet hammizrāqôt ʾăšer zāhāḇ zāhāḇ wᵉʾăšer kesep kesep</em> — the firepans and bowls, whatever was of gold (took the gold ones), of silver (took the silver ones) — the repeated noun-noun construction (<em>zāhāḇ zāhāḇ</em>, gold gold; <em>kesep kesep</em>) is an emphatic distributive: every golden item, every silver item, was taken without exception. <em>rab ṭabbāḥîm lāqāḥ</em> — the captain of the guard took — the subject returns to Nebuzaradan as the agent of systematic despoliation; the temple&rsquo;s wealth, accumulated through generations of Davidic kingship and Solomon&rsquo;s construction program, is removed in a single systematic sweep.</p>",
    "16": "<p><em>hāʿammûḏîm šᵉnayim hayyām ʾeḥāḏ wᵉhammᵉkônôt ʾăšer ʿāśāh šᵉlōmōh lᵉḇêt YHWH</em> — the two pillars, the one sea, and the stands that Solomon had made for the house of YHWH — the inventory returns to the largest objects, referencing Solomon&rsquo;s original craftsmanship. The phrase <em>lōʾ hāyāh mišqal linnᵉḥōšet kol hakkēlîm hāʾēlleh</em> (the bronze of all these vessels was beyond weighing) is an echo of 1 Kings 7:47 where Solomon&rsquo;s bronze work was &lsquo;not weighed because it was too vast&rsquo; — what could not be weighed because of its abundance is now carried away because of the nation&rsquo;s sin. The quantity that exceeded measurement in covenant flourishing now exceeds measurement as the object of judgment&rsquo;s plunder.</p>",
    "17": "<p><em>šᵉmōneh ʿeśrēh ʾammāh qômāh hāʿammûḏ hāʾeḥāḏ</em> — eighteen cubits the height of one pillar — the precise measurement (18 cubits ≈ 27 feet) reflects the narrator&rsquo;s care to preserve the architectural memory of what was lost. The detailed description of the capital (the bronze <em>kōteret</em>, the pomegranates, the latticework) echoes the original construction account of 1 Kings 7:15-22 in miniature, as if the destruction narrative itself functions as an architectural memorial. The twelve pomegranates on the latticework — twelve suggesting the twelve tribes — mean that the destruction of the pillars is also the material end of the twelve-tribe covenant symbol. <em>kēn lāʿammûḏ haššēnî ʿal haśśᵉḇāḵāh</em> — so for the second pillar, with the latticework — the symmetry of the original construction is matched by the symmetry of its documentation at destruction.</p>",
    "18": "<p><em>wayyiqqaḥ rab ṭabbāḥîm ʾet śᵉrāyāh kōhēn hārōʾš wᵉʾet ṣᵉp̄anyāh kōhēn hammiššneh</em> — the captain of the guard took Seraiah the chief priest and Zephaniah the second priest — the priestly leadership is deported alongside the political leadership; the covenant&rsquo;s two institutional pillars (monarchy and priesthood) are both removed. <em>ûšᵉlōšet šōmᵉrê hassap</em> — and the three doorkeepers — the <em>šōmᵉrê hassap</em> (threshold guardians) are the Levitical gatekeepers of 2 Kings 12:9; their deportation ends the Levitical guard function at the threshold that had been maintained since the Deuteronomic reform. The doorkeepers of the covenant house are taken; there is no longer a threshold to guard.</p>",
    "19": "<p><em>ûmin hāʿîr lāqaḥ sārîs ʾeḥāḏ</em> — from the city he took one official — the term <em>sārîs</em> (eunuch/official) designates royal court functionaries who managed palace administration. The itemized deportees in v19 — an official, five men of the king&rsquo;s council (<em>rōʾê pᵉnê hammelek</em>, those who saw the king&rsquo;s face — the idiom for inner-circle courtiers), the military secretary, sixty men of the land — represent a comprehensive sweep of the civil and military administrative class. The phrase <em>rōʾê pᵉnê hammelek</em> (those who see the king&rsquo;s face) is a court-protocol idiom: access to the king&rsquo;s face defined the hierarchy of intimacy; these are the innermost circle, and they are deported precisely because they are the most dangerous to leave behind.</p>",
    "20": "<p><em>wayyiqqaḥ ʾōtām nᵉḇûzarʾaḏān rab ṭabbāḥîm wayyōlēk ʾōtām ʾel melek bāḇel riblātāh</em> — Nebuzaradan the captain of the guard took them and brought them to the king of Babylon at Riblah — the deportation of the priestly and civil leadership to Riblah for judgment creates a structural parallel with v6 (Zedekiah brought to Riblah) and with 23:33 (Jehoahaz brought to Riblah by Pharaoh Necho). Three times in 2 Kings a Judean leader or group is brought to Riblah for foreign judgment; the repetition establishes Riblah as the locus of covenant accountability that Jerusalem itself failed to be. The judgment that should have been executed in the king&rsquo;s court in Jerusalem is now carried out in a foreign court in Syria.</p>",
    "21": "<p><em>wayyak ʾōtām melek bāḇel wayyᵉmîtēm bᵉriblāh bᵉʾereṣ ḥamāt</em> — the king of Babylon struck them down and put them to death at Riblah in the land of Hamath — <em>nākāh</em> (struck) is the standard execution verb; <em>mût</em> (hiphil: caused to die/put to death) completes the judicial sentence. The death of the priests and officials at Riblah fulfills the prophetic warnings about the fate of those who led Israel astray (cf. Jer 52:24-27 parallels this passage closely). <em>wayyigel yᵉhûḏāh mēʿal ʾaḏmātô</em> — Judah was exiled from its land — the summary statement of the chapter&rsquo;s theological verdict: <em>gālāh</em> (was exiled/went into exile), the verb from which &lsquo;golah&rsquo; (exile) derives, expressing the stripping-away of the covenant people from their covenant land.</p>",
    "22": "<p><em>wᵉhāʿām hannišʾār bᵉʾereṣ yᵉhûḏāh</em> — the people who remained in the land of Judah — <em>nišʾār</em> (remained/was left over) is the remnant vocabulary; the &lsquo;remaining ones&rsquo; are those not deported, now to be governed by Gedaliah. <em>wayyapqēḏ ʿălêhem nᵉḇûḵaḏneʾṣṣar melek bāḇel ʾet gᵉḏalyāhû ben ʾăḥîqām ben šāpān</em> — Nebuchadnezzar appointed over them Gedaliah son of Ahikam son of Shaphan — the name Gedaliah (YHWH is great) and the lineage (Shaphan was the scribe who brought the lawbook to Josiah, 22:8; Ahikam protected Jeremiah, Jer 26:24) give Gedaliah strong covenant credentials. The appointment by the Babylonian king of a man from a family of covenant-fidelity is a small grace-note within the disaster narrative.</p>",
    "23": "<p><em>wayyišmᵉʿû kol śārê haḥăyālîm hēmmāh wᵉhāʾănāšîm</em> — when all the captains of the forces heard, they and the men with them — the grammar marks the captains as the subject of the hearing: they receive the report and come to Gedaliah. The list of captains — Ishmael ben Netaniah, Johanan ben Kareah, Seraiah ben Tanhumeth the Netophathite, Jaazaniah son of the Maacathite — is a remnant military roster; these are the guerrilla commanders who had survived outside the city during the siege. Their coming to Gedaliah at Mizpah represents a potential reconstitution of Judean society around a non-Davidic but covenant-faithful administrator. <em>hammiṣpātāh</em> — to Mizpah — the place where Samuel had gathered Israel (1 Sam 7:5-12); Mizpah functions as an alternative covenant-assembly site when Jerusalem is unavailable.</p>",
    "24": "<p><em>wayyiššābaʿ lāhem gᵉḏalyāhû wᵉlāʾănāšêhem wayyōʾmer lāhem</em> — Gedaliah swore to them and their men and said to them — <em>nišbaʿ</em> (sworn) marks a formal covenant-like assurance; Gedaliah&rsquo;s oath to the captains is the basis for their settlement under his administration. <em>ʾal tîrᵉʾû mēʿaḇdê kaśḏîm šᵉḇû bāʾāreṣ wᵉʿiḇdû ʾet melek bāḇel wᵉîṭaḇ lākem</em> — do not be afraid of the servants of the Chaldeans; dwell in the land and serve the king of Babylon and it will go well with you — the imperative <em>šᵉḇû</em> (remain/dwell) activates the theology of the land: the covenant people should remain in the land even under foreign rule rather than flee (cf. Jer 42:10-12, the same counsel from Jeremiah). The <em>ṭôḇ</em> (good/well) echoes the covenant blessing of Deut 6:3, now mediated through a Babylonian client governor.</p>",
    "25": "<p><em>wayhî baḥōḏeš haššᵉḇîʿî</em> — in the seventh month — another precise date marking the third disaster of ch25: assassination of Gedaliah. <em>bāʾ yišmāʾēl ben nᵉtanyāh ben ʾĕlîšāmāʿ mizzaraʿ hammlûḵāh</em> — Ishmael son of Netaniah son of Elishama of the royal seed — <em>mizzaraʿ hammlûḵāh</em> (of the royal seed) identifies Ishmael as a Davidide, making the assassination a dynastic murder: a member of the royal family kills the governor. <em>wayyak ʾet gᵉḏalyāhû wayyāmōt</em> — he struck Gedaliah and he died — the same verb-pair as v21 (the executions at Riblah); Gedaliah&rsquo;s death by assassination mirrors the official executions of the deported leaders, compounding the disaster. The murder of the one remnant leader who represented covenant continuity destroys the last organized structure of Judean life in the land.</p>",
    "26": "<p><em>wayyāqom kol hāʿām miqqāṭōn wᵉʿaḏ gāḏôl wᵉśārê haḥăyālîm wayyāḇōʾû miṣrāyim</em> — all the people, both small and great, and the captains of the forces arose and came to Egypt — <em>miqqāṭōn wᵉʿaḏ gāḏôl</em> (from small to great) is the covenant-totality formula indicating that the entire remaining community is included in the flight. The flight to Egypt is the ultimate covenant reversal: the Exodus had been from Egypt to Canaan; now the covenant people flee back to Egypt. The verb <em>bōʾ miṣrāyim</em> (came to Egypt) is the exact opposite of <em>yāṣāʾ mimiṣrāyim</em> (went out from Egypt) of the Exodus formula. <em>kî yārᵉʾû mipĕnê kaśḏîm</em> — for they were afraid of the Chaldeans — fear of the Babylonians drives them back to the land of bondage; the fear that the Exodus was meant to cure (YHWH as the one to fear) is replaced by fear of a human empire.</p>",
    "28": "<p><em>wayyᵉdabbēr ʾittô ṭōḇôt wayyittēn ʾet kissĕʾô mimmʿal kissēʾ hammlāḵîm ʾăšer ʾittô bāḇel</em> — he spoke kindly with him and set his throne above the thrones of the kings who were with him in Babylon — <em>dibbēr ṭōḇôt</em> (spoke good things/kindly) is the vocabulary of grace and favor; the Babylonian king&rsquo;s speech to Jehoiachin inverts Nebuchadnezzar&rsquo;s earlier speech of judgment at Riblah. <em>miмmaʿal kissēʾ</em> (above the throne) — the elevation above other subject-kings is a formal honor in the Babylonian court hierarchy. The throne above thrones language is the grammar of the Davidic promise (Ps 89:27: &lsquo;I will make him the firstborn, the highest of the kings of the earth&rsquo;), here being approximated in Babylonian exile by a foreign king&rsquo;s grace.</p>",
    "29": "<p><em>wᵉšinnāh ʾēt bigḏê kilĕʾô</em> — he changed his prison garments — the changing of garments is a covenant-status marker throughout the OT: Joseph&rsquo;s prison garments changed before Pharaoh (Gen 41:14), the leprous garment as mark of uncleanness (Lev 13), the high priest&rsquo;s change of garments at Yom Kippur (Lev 16:23-24). Jehoiachin&rsquo;s change from prison clothes to regular clothes is a form of ceremonial re-entry into the court community — a limited restoration of dignity without a restoration of power. <em>wᵉʾāḵal leḥem lᵉpānāyw tāmîḏ kol yᵉmê ḥayyāyw</em> — he ate bread before him continually all the days of his life — <em>leḥem lᵉpānāyw</em> (bread before him) is the idiom for eating at the king&rsquo;s table, precisely the honor that Mephibosheth received from David (2 Sam 9:7, 10, 13): the covenant-kindness (<em>ḥeseḏ</em>) extended to the remnant of the previous dynasty.</p>",
    "30": "<p><em>wᵉʾaryōḥô tāmîḏ nittān lô mēʾet hammelek</em> — and his regular allowance was given him by the king — <em>ʾaryōḥô</em> (his regular allowance/ration) is a hapax legomenon in the OT, possibly related to an Akkadian term for a food ration; archaeological tablets from Babylon (the Weidner tablets) mention rations for &lsquo;Yaukin king of Judah&rsquo; and his sons, providing extra-biblical confirmation of this narrative. <em>dᵉḇar yôm bᵉyômô</em> — a daily portion for each day — the same formula used for the daily bread of the wilderness manna (Exod 16:4, <em>dᵉḇar yôm bᵉyômô</em>); the daily provision of the exile recalls the daily provision of the wilderness, both sustained by a sovereign outside Israel&rsquo;s control. The book ends with the Davidic seed alive, receiving daily bread in a foreign land — a small, ambiguous ember of covenant hope.</p>"
  }
}

def main():
    c = load_comm('mkt-original', '2kings')
    merge_comm(c, FILL)
    save_comm('mkt-original', '2kings', c)

    import json as _j
    inter = _j.load(open(ROOT / 'data' / 'interlinear' / '2kings.json'))
    incomplete = []
    for ch in ['24', '25']:
        total = len(inter[str(ch)])
        have = len(c.get(str(ch), {}))
        if have < total:
            miss = [v for v in inter[str(ch)] if str(v) not in c.get(str(ch), {})]
            incomplete.append(f'ch{ch}: {have}/{total} missing {sorted(miss, key=int)}')
        else:
            print(f'  ch {ch}: complete ({total}/{total})')
    if incomplete:
        for s in incomplete:
            print(f'  {s}')
    total_i = sum(len(v) for v in inter.values())
    total_h = sum(len(v) for v in c.values())
    print(f'  Overall 2kings/original: {total_h}/{total_i}')

if __name__ == '__main__':
    main()
